sql_answer:
SELECT
  100.0 * SUM(CASE WHEN m.built_year < 1850 THEN 1 ELSE 0 END) / NULLIF(COUNT(*), 0) AS percentage_mills_built_before_1850
FROM mill AS m;

SELECT COUNT(*) AS architect_count
FROM architect AS a
WHERE a.nationality IN ('American', 'German');

SELECT
  100.0 * SUM(CASE WHEN ev.fault_status = 'Fixed' THEN 1 ELSE 0 END) / NULLIF(COUNT(*), 0) AS percent_completed
FROM Engineer_Visits AS ev;
